initial_candidates.sql:
SELECT ABS(
    (SELECT COUNT(*) FROM trans t JOIN account a ON t.account_id = a.account_id JOIN district d ON a.district_id = d.district_id WHERE d.A2 LIKE 'E%' AND strftime('%Y', t.date) = '1996') -
    (SELECT COUNT(*) FROM trans t JOIN account a ON t.account_id = a.account_id JOIN district d ON a.district_id = d.district_id WHERE d.A2 LIKE 'N%' AND strftime('%Y', t.date) = '1996')
) AS crime_difference;
